import{_ as t,o,c as a,ag as n}from"./chunks/framework.C9sp7nFj.js";const s="/screenshots/checkin-map.jpeg",i="/screenshots/checkin-history.jpeg",k=JSON.parse('{"title":"Check-in & Check-out","description":"","frontmatter":{},"headers":[],"relativePath":"guide/check-in.md","filePath":"guide/check-in.md","lastUpdated":1776880543000}'),r={name:"guide/check-in.md"};function h(c,e,l,d,u,g){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="check-in-check-out" tabindex="-1">Check-in &amp; Check-out <a class="header-anchor" href="#check-in-check-out" aria-label="Permalink to &quot;Check-in &amp; Check-out&quot;">​</a></h1><p>The core of the app. Here&#39;s everything about the Check-in screen.</p><div class="tip custom-block"><p class="custom-block-title">Two modes</p><p>Your HR team configures whether the big <strong>Check In</strong> button writes attendance directly (<em>Checkin Based</em>, the default) or first asks you to pick a task (<em>Timer Based</em>). The rest of this page describes the default. For the task-picker variant, see <strong><a href="#timer-based-flow">&quot;Timer Based&quot; flow</a></strong> below.</p></div><h2 id="open-the-screen" tabindex="-1">Open the screen <a class="header-anchor" href="#open-the-screen" aria-label="Permalink to &quot;Open the screen&quot;">​</a></h2><p>From the home screen, tap the big <strong>&quot;Check In&quot;</strong> (or <strong>&quot;Check Out&quot;</strong> if you&#39;re already IN) button in the top card.</p><figure class="screenshot"><img src="'+s+'" alt="Check-in screen with map"><figcaption>The Check-in screen — OpenStreetMap preview of your GPS fix, reverse-geocoded address, geofence chip, and the big Check Out button.</figcaption></figure><h2 id="what-the-screen-shows" tabindex="-1">What the screen shows <a class="header-anchor" href="#what-the-screen-shows" aria-label="Permalink to &quot;What the screen shows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>What it is</th></tr></thead><tbody><tr><td><strong>Map preview</strong></td><td>A small OpenStreetMap view centered on your current GPS location</td></tr><tr><td><strong>Address</strong></td><td>Reverse-geocoded street address of your location (when online)</td></tr><tr><td><strong>Geofence chip</strong></td><td>Whether you&#39;re inside / outside your task radius (if a task is assigned)</td></tr><tr><td><strong>Selfie slot</strong></td><td>Shown only if your company requires selfies</td></tr><tr><td><strong>Big button</strong></td><td>&quot;Check In&quot; or &quot;Check Out&quot; depending on your current state</td></tr><tr><td><strong>Check-in history →</strong></td><td>Link to see all your past check-ins</td></tr></tbody></table><h2 id="first-time-permission-prompts" tabindex="-1">First-time permission prompts <a class="header-anchor" href="#first-time-permission-prompts" aria-label="Permalink to &quot;First-time permission prompts&quot;">​</a></h2><p>The first time you use Check-in, Android asks for:</p><ul><li><strong>Location</strong> — required. The app needs your GPS coordinates to record where you checked in. Tap <strong>Allow</strong>.</li><li><strong>Camera</strong> — only if your company uses selfie mode. Tap <strong>Allow</strong> the first time you take a selfie.</li></ul><p>If you accidentally tap <strong>Deny</strong>, go to Android <strong>Settings → Apps → Fateh HR Demo → Permissions</strong> and grant them there.</p><h2 id="doing-a-check-in" tabindex="-1">Doing a check-in <a class="header-anchor" href="#doing-a-check-in" aria-label="Permalink to &quot;Doing a check-in&quot;">​</a></h2><ol><li>Let the map settle — it takes 1–3 seconds to get your GPS coordinates.</li><li>If selfie is required, tap the <strong>Selfie</strong> slot and take a photo.</li><li>Tap <strong>Check In</strong>.</li><li>You feel a soft haptic buzz → message says <strong>&quot;Recorded.&quot;</strong> (online) or <strong>&quot;Queued — will sync when online.&quot;</strong> (offline).</li><li>The app automatically sends you back to the home screen after a moment.</li></ol><h2 id="the-check-out-flow" tabindex="-1">The Check Out flow <a class="header-anchor" href="#the-check-out-flow" aria-label="Permalink to &quot;The Check Out flow&quot;">​</a></h2><p>Identical — just tap <strong>&quot;Check Out&quot;</strong>. The button label and the entry&#39;s IN/OUT tag change based on your last action. So the app always knows what &quot;the next action&quot; should be.</p><h2 id="getting-gps-location-—-what-s-happening" tabindex="-1">&quot;Getting GPS location…&quot; — what&#39;s happening <a class="header-anchor" href="#getting-gps-location-—-what-s-happening" aria-label="Permalink to &quot;&quot;Getting GPS location…&quot; — what&#39;s happening&quot;">​</a></h2><p>If you see this message, your phone is still resolving your position. Common causes:</p><ul><li><strong>You&#39;re indoors or underground</strong> — GPS signal is weak or blocked</li><li><strong>Just turned on location services</strong> — first fix takes 10–30 s</li><li><strong>Airplane mode / battery saver</strong> has disabled GPS</li></ul><p>The app gives it ~8 seconds. If no coords arrive, you see <strong>&quot;Can&#39;t get GPS. Grant location permission, then tap Check In again.&quot;</strong> — check the permission and retry.</p><h2 id="the-geofence-chip" tabindex="-1">The geofence chip <a class="header-anchor" href="#the-geofence-chip" aria-label="Permalink to &quot;The geofence chip&quot;">​</a></h2><p>If your HR team has configured a task with a location and radius, the app checks whether you&#39;re inside that radius.</p><table tabindex="0"><thead><tr><th>Chip</th><th>Meaning</th></tr></thead><tbody><tr><td>🟢 <strong>Within task radius</strong></td><td>You&#39;re at the right place. Check-in will be accepted as &quot;inside&quot;.</td></tr><tr><td>🟠 <strong>Outside task radius — will be flagged</strong></td><td>You&#39;re away from the assigned location. The check-in still records but your manager will see it was off-site.</td></tr><tr><td>⚪ <strong>Location unavailable</strong></td><td>GPS isn&#39;t ready yet. Wait a moment.</td></tr><tr><td>⚪ <strong>No task radius set</strong></td><td>Your task doesn&#39;t have a geofence. No location rule applies.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The geofence rule is set by your HR / manager per task. Being &quot;Outside&quot; doesn&#39;t block you from checking in — it&#39;s just flagged for review.</p></div><h2 id="viewing-your-check-in-history" tabindex="-1">Viewing your check-in history <a class="header-anchor" href="#viewing-your-check-in-history" aria-label="Permalink to &quot;Viewing your check-in history&quot;">​</a></h2><p>Tap <strong>Check-in history →</strong> at the bottom of the Check-in screen. You&#39;ll see:</p><ul><li>Every check-in you&#39;ve done, most recent first</li><li>An <strong>up arrow (↓)</strong> on a green badge for IN</li><li>A <strong>down arrow (↑)</strong> on a grey badge for OUT</li><li>The location address or task name</li><li>The exact time (hours + minutes + seconds)</li></ul><figure class="screenshot"><img src="'+i+'" alt="Full Check-in history list"><figcaption>Check-in history — chronological list of IN / OUT events with second-level timestamps so quick repeat taps are still distinguishable.</figcaption></figure><p>On the home screen, the last <strong>3</strong> check-ins are also shown in the &quot;Check-in history&quot; card for quick reference.</p><h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Message</th><th>What to do</th></tr></thead><tbody><tr><td>&quot;Please take a selfie to continue.&quot;</td><td>Your company requires one. Tap the selfie slot first.</td></tr><tr><td>&quot;Can&#39;t get GPS.&quot;</td><td>See permission / GPS section above.</td></tr><tr><td>&quot;Queued — will sync when online.&quot;</td><td>Normal for offline mode. It will sync automatically when network returns.</td></tr><tr><td>App stuck on &quot;Finding your location…&quot;</td><td>Wait up to 10 s, then tap Check In again. Or restart the app.</td></tr></tbody></table><h2 id="timer-based-flow" tabindex="-1">&quot;Timer Based&quot; flow <a class="header-anchor" href="#timer-based-flow" aria-label="Permalink to &quot;&quot;Timer Based&quot; flow&quot;">​</a></h2><p>If your HR admin has set <strong>Attendance Mode</strong> to <em>Timer Based</em>, the Check-In button works a little differently:</p><ol><li>You tap <strong>Check In</strong> on the home screen.</li><li>The Check-in screen asks you to <strong>pick a task</strong> from your assigned list before you can proceed.</li><li>You select a task, the app captures GPS, and taps <strong>Check In</strong>.</li><li>Server creates an <strong>Employee Checkin (IN)</strong> plus a running <strong>Timesheet</strong> row tied to that task.</li><li>On the Tasks tab, that same task now shows a running timer — same timer, viewed two ways.</li></ol><h3 id="checking-out-in-timer-mode" tabindex="-1">Checking out in Timer mode <a class="header-anchor" href="#checking-out-in-timer-mode" aria-label="Permalink to &quot;Checking out in Timer mode&quot;">​</a></h3><ol><li>Tap <strong>Check Out</strong> from home.</li><li>The app shows the running task name and the elapsed time on the Check-in screen.</li><li>Tap <strong>Check Out</strong> → the running timer stops, the Timesheet row closes with hours, and an <strong>Employee Checkin (OUT)</strong> is written.</li></ol><h3 id="switching-task-mid-day" tabindex="-1">Switching task mid-day <a class="header-anchor" href="#switching-task-mid-day" aria-label="Permalink to &quot;Switching task mid-day&quot;">​</a></h3><p>Stop on one task (Check Out) then Check In again with a different task. You&#39;ll get two attendance pairs for the day — one per task.</p><h3 id="no-tasks-assigned" tabindex="-1">No tasks assigned? <a class="header-anchor" href="#no-tasks-assigned" aria-label="Permalink to &quot;No tasks assigned?&quot;">​</a></h3><p>You&#39;ll see &quot;No tasks assigned.&quot; Message your HR team — in this mode they need to assign at least one open task before you can check in.</p><p>See <strong><a href="/guide/attendance-mode">Attendance mode</a></strong> for the full logic.</p><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/offline">How offline mode works</a> — essential reading for field staff</li><li><a href="/guide/attendance">Attendance calendar</a></li><li><a href="/guide/attendance-mode">Attendance mode</a> — why your check-in screen looks like it does</li></ul>',43)])])}const m=t(r,[["render",h]]);export{k as __pageData,m as default};
